+        for (uint j = 1; j < n->req(); ++j) {
+          Node* in = n->in(j);
+          if (in == nullptr) {
+            continue;
+          }
+          _nodes_from_phi.push(in);
+        }
+      } else if (n->is_ConstraintCast()) {
+        Node* in = n->in(1);
+        if (in == nullptr) {
+          continue;
+        }
+        _nodes_from_phi.push(in);
+      }
+    }
